// Solution
public int findLengthOfLCIS(int[] nums) {
    if (nums.length == 0) return 0;
    int[] dp = new int[nums.length];
    for (int i = 0; i < nums.length; i++) {
        dp[i] = 1;
    }
    int maxLen = 0;
    for (int i = 1; i < nums.length; i++) {
        if (nums[i] > nums[i - 1]) {
            dp[i] = dp[i - 1] + 1;
        }
    }
    maxLen = Arrays.stream(dp).max().getAsInt();
    return maxLen;
}

