// Solution
function findLengthOfLCIS(nums) {
    if (nums.length == 0) return 0;
    let dp = new Array(nums.length).fill(1);
    let maxLen = 0;
    for (let i = 1; i < nums.length; i++) {
        if (nums[i] > nums[i - 1]) {
            dp[i] = dp[i - 1] + 1;
        }
    }
    maxLen = Math.max(...dp);
    return maxLen;
}
